function validatePath(
  filePath: unknown,
  pathName: "cache" | "artifacts" | "tests" | "sources",
  index?: number,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (typeof filePath !== "string") {
    const messagePrefix =
      index !== undefined
        ? `paths.${pathName} at index ${index}`
        : `paths.${pathName}`;

    validationErrors.push({
      path:
        index !== undefined ? ["paths", pathName, index] : ["paths", pathName],
      message: `${messagePrefix} must be a string`,
    });
  }

  return validationErrors;
}

protected async _getRawValue(): Promise<string> {
  const mutex = LazyResolvedConfigurationVariable.#mutexes.get(this.#hooks);
  assertHardhatInvariant(mutex !== undefined, "Mutex must be defined");

  return await mutex.exclusiveRun(
    async () =>
      await this.#hooks.runHandlerChain(
        "configurationVariables",
        "fetchValue",
        [this.#variable],
        async (_context, v) => {
          const value = process.env[v.name];

          if (typeof value !== "string") {
            throw new HardhatError(
              HardhatError.ERRORS.CORE.GENERAL.ENV_VAR_NOT_FOUND,
              { name: v.name },
            );
          }

          return value;
        },
      ),
  );
}

function validateTaskArgumentValue(
  name: string,
  expectedType: ArgumentType,
  value: ArgumentValue | ArgumentValue[],
  isVariadic: boolean,
  taskId: string | string[],
): void {
  try {
    validateArgumentValue(name, expectedType, value, isVariadic);
  } catch (error) {
    if (
      HardhatError.isHardhatError(
        error,
        HardhatError.ERRORS.CORE.ARGUMENTS.INVALID_VALUE_FOR_TYPE,
      )
    ) {
      throw new HardhatError(
        HardhatError.ERRORS.CORE.TASK_DEFINITIONS.INVALID_VALUE_FOR_TYPE,
        {
          name,
          type: expectedType,
          value,
          task: formatTaskId(taskId),
        },
      );
    }

    throw error;
  }
}

function getVariable(prefix: string, name: string): string | SensitiveString | undefined {
	// We transform dash into underscore as dash are not supported everywhere in env var names
	const variableName = (prefix + name).replaceAll('-', '_');
	let uri = process.env[variableName];
	if (uri === 'SECRET') {
		return configVariable(`SECRET_${variableName}`);
	} else if (uri?.startsWith('SECRET:')) {
		const splitted = uri.split(':');
		if (splitted.length !== 2) {
			throw new Error(`invalid secret uri ${uri}`);
		}
		return configVariable(`SECRET_${prefix + splitted[1]}`);
	}
	return uri;
}

export function getRPC(networkName: string): string | SensitiveString | undefined {
	let uri = getVariable('ETH_NODE_URI_', networkName);

	if (uri && uri !== '') {
		return uri;
	}

	uri = process.env.ETH_NODE_URI;
	if (uri) {
		uri = uri.replace('{{networkName}}', networkName);
	}
	if (!uri || uri === '') {
		if (networkName === 'localhost') {
			return 'http://localhost:8545';
		}
		return uri;
		// throw new Error(`no uri specified or for network ${networkName}`);
	}
	if (uri.indexOf('{{') >= 0) {
		throw new Error(`invalid uri or network not supported by node provider : ${uri}`);
	}

	return uri;
}

