public static getCompilerPlatformBinary(arch = os.arch()): CompilerPlatformBinary {
  if (arch !== "x64" && arch !== "arm64") {
    return CompilerPlatformBinary.WASM;
  }

  switch (os.platform()) {
    case "win32":
      return arch === "arm64" ? CompilerPlatformBinary.WINDOWS_ARM : CompilerPlatformBinary.WINDOWS_AMD;
    case "linux":
      return arch === "arm64" ? CompilerPlatformBinary.LINUX_ARM : CompilerPlatformBinary.LINUX_AMD;
    case "darwin":
      return arch === "arm64" ? CompilerPlatformBinary.MACOS_ARM : CompilerPlatformBinary.MACOS_AMD;
    default:
      return CompilerPlatformBinary.WASM;
  }
}

function getZkvyperUrl(repo: string, version: string, isRelease: boolean = true): string {
    // @ts-ignore
    const platform = { darwin: 'macosx', linux: 'linux', win32: 'windows' }[process.platform];
    const toolchain = semver.lt(version, COMPILER_MIN_LINUX_VERSION_WITH_GNU_TOOLCHAIN)
        ? // @ts-ignore
          { linux: '-musl', win32: '-gnu', darwin: '' }[process.platform]
        : // @ts-ignore
          { linux: '-gnu', win32: '-gnu', darwin: '' }[process.platform];
    const arch = process.arch === 'x64' ? 'amd64' : process.arch;
    const ext = process.platform === 'win32' ? '.exe' : '';

    if (isRelease) {
        return `${repo}/releases/download/${version}/zkvyper-${platform}-${arch}${toolchain}-v${version}${ext}`;
    }

    return `${repo}/raw/main/${platform}-${arch}/zkvyper-${platform}-${arch}${toolchain}-v${version}${ext}`;
}

function calculateBatchDisplay(state: UiState): {
  text: string;
  height: number;
} {
  const batch = state.batches[state.currentBatch - 1];
  const height = batch.length + (state.ledgerMessageIsDisplayed ? 4 : 2);

  let text = `Batch #${state.currentBatch}\n`;

  text += batch
    .sort((a, b) => a.futureId.localeCompare(b.futureId))
    .map((v) => _futureStatus(v, state.gasBumps, state.maxFeeBumps))
    .join("\n");

  text += "\n";

  if (state.ledger) {
    text += `\n  Ledger: ${state.ledgerMessage}\n`;
  }

  return { text, height };
}

function getCompilerAsset(): CompilerAsset {
    const platform = os.platform();
    const arch = os.arch();

    if (platform === "linux" && arch === "x64") {
        return {
            name: "release-x86_64-unknown-linux-musl.tar.gz",
            isGzipped: true
        };
    } else if (platform === "darwin" && arch === "arm64") {
        return {
            name: "release-aarch64-apple-darwin.tar",
            isGzipped: false
        };
    }

    throw new Error(
        `Unsupported combination of platform (${platform}) and architecture (${arch}). Consider using a custom compiler (cairo1BinDir in config).`
    );
}

private async prepareDockerArgs(): Promise<string[]> {
    const { rootPath, container } = this;
    const formattedImage = `${this.image.repository}:${this.image.tag}`;
    const binds = {
        [rootPath]: "/src"
    };

    const cmd = this.getCommand();

    const dockerArgs = ["--rm", "-i", "--name", container];

    this.cairoPathBindings(binds, dockerArgs);

    Object.keys(binds).forEach((k) => {
        dockerArgs.push("-v");
        dockerArgs.push(`${k}:${binds[k]}`);
    });

    const entrypoint = cmd.shift();

    await this.ensureDockerImage(formattedImage);

    return [...dockerArgs, "--entrypoint", entrypoint, formattedImage, ...cmd];
}

public async run(args: { script?: boolean }) {
    if (!this.docker) {
        this.docker = await HardhatDocker.create();
    }

    this.useShell = !!args.script;

    const dockerArgs = await this.prepareDockerArgs();

    console.log("Running amarna, this may take a while.");

    const result = spawnSync("docker", ["run", ...dockerArgs]);

    const defaultOutput = ` at ${this.rootPath}/${DEFAULT_OUTPUT}`;
    console.log(`Sarif file generated${this.useShell ? "" : defaultOutput}`);

    // Output the output/error for user to review.
    result.stdout && console.log(result.stdout.toString());
    result.stderr && console.error(result.stderr.toString());
}

protected async getDockerArgs(): Promise<string[]> {
    // To access the files on host machine from inside the container, proper mounting has to be done.
    const volumes = ["-v", `${PROXY_SERVER_HOST_PATH}:${PROXY_SERVER_CONTAINER_PATH}`];
    volumes.push("-v", `${LEGACY_CLI_HOST_PATH}:${LEGACY_CLI_CONTAINER_PATH}`);

    for (const mirroredPath of [this.rootPath, ...this.cairoPaths]) {
        volumes.push("-v", `${mirroredPath}:${mirroredPath}`);
    }

    const dockerArgs = [...volumes];

    // Check if Docker Desktop
    if (this.isDockerDesktop) {
        this.port = await this.getPort();
        dockerArgs.push("-p", `${this.port}:${this.port}`);
    } else {
        dockerArgs.push("--network", "host");
    }

    return dockerArgs;
}

async function getResolvedRemoteContracts(
  provider: EthereumProvider,
  remoteContracts: RemoteContract[] = []
): Promise<RemoteContract[]> {
  const { default: sha1 } = await import("sha1");
  for (const contract of remoteContracts) {
    try {
      contract.bytecode = await provider.send("eth_getCode", [contract.address, "latest"]);
      contract.deployedBytecode = contract.bytecode;
      contract.bytecodeHash = sha1(contract.bytecode!);
    } catch (error: any) {
      console.log(
        `hardhat-gas-reporter:warning: failed to fetch bytecode for remote contract: ${contract.name}`
      );
      console.log(`Error was: ${error}\n`);
    }
  }
  return remoteContracts;
}

function gasToCost(
  executionGas: number,
  calldataGas: number,
  options: GasReporterOptions
): string {
  let calldataCost: number = 0;

  if (options.L2) {
    const cost = getCalldataCostForNetwork(options, calldataGas);
    if (options.L2 === "optimism" || options.L2 === "base") {
      calldataCost =  (cost / 1e9) * parseFloat(options.tokenPrice!);
    }
    if (options.L2 === "arbitrum") {
      executionGas += cost;
    }
  }
  const executionCost = (options.gasPrice! / 1e9) * executionGas * parseFloat(options.tokenPrice!);
  return (executionCost + calldataCost).toFixed(options.currencyDisplayPrecision);
}

function applyErrorMessageTemplate(
  template: string,
  values: Record<string, ErrorMessageTemplateValue>,
): string {
  return template.replaceAll(/{(.*?)}/g, (_match, variableName) => {
    const rawValue = values[variableName];

    if (rawValue === undefined) {
      return "undefined";
    }

    if (rawValue === null) {
      return "null";
    }

    if (typeof rawValue === "bigint") {
      return `${rawValue}n`;
    }

    if (Array.isArray(rawValue)) {
      return JSON.stringify(rawValue);
    }

    return rawValue.toString();
  });
}

