const copyFile = (
	source: string,
	target: string,
	replacements: Record<string, string> = {},
	gitignorePatterns: string[] = [],
): void => {
	const fileName = basename(source);

	// Check if file should be skipped based on gitignore patterns
	for (const pattern of gitignorePatterns) {
		if (fileName === pattern || fileName.endsWith(pattern.replace('*', ''))) {
			return; // Skip this file
		}
	}

	let content = readFileSync(source, 'utf-8');

	// Apply replacements
	for (const [search, replace] of Object.entries(replacements)) {
		content = content.replaceAll(search, replace);
	}

	mkdirSync(dirname(target), {recursive: true});

	// For binary files, just copy as-is
	if (source.endsWith('.lock') || source.endsWith('.so') || source.endsWith('.wasm')) {
		copyFileSync(source, target);
	} else {
		writeFileSync(target, content, 'utf-8');
	}
};

export function traverse(
	dir: string,
	result: any[] = [],
	topDir?: string,
	filter?: (name: string, stats: any) => boolean, // TODO any is Stats
): Array<FileTraversed> {
	fs.readdirSync(dir).forEach((name) => {
		const fPath = path.resolve(dir, name);
		const stats = fs.statSync(fPath);
		if ((!filter && !name.startsWith('.')) || (filter && filter(name, stats))) {
			const fileStats = {
				name,
				path: fPath,
				relativePath: path.relative(topDir || dir, fPath),
				mtimeMs: stats.mtimeMs,
				directory: stats.isDirectory(),
			};
			if (fileStats.directory) {
				result.push(fileStats);
				return traverse(fPath, result, topDir || dir, filter);
			}
			result.push(fileStats);
		}
	});
	return result;
}

async #toRpcSig(sig: Signature): Promise<string> {
  if (microEthSignerUtils === undefined) {
    microEthSignerUtils = await import("micro-eth-signer/utils");
  }

  const recovery = this.#calculateSigRecovery(sig.v - 27);

  assertHardhatInvariant(
    recovery === 0 || recovery === 1,
    `Invalid recovery value: ${recovery}. It should be either 0 or 1.`,
  );

  const nobleSig = microEthSignerUtils.initSig(
    { r: toBigInt(`0x${sig.r}`), s: toBigInt(`0x${sig.s}`) },
    recovery,
  );

  const hex64 = nobleSig.toCompactHex();
  const vByte = recovery === 0 ? "1b" : "1c";

  return microEthSignerUtils.add0x(hex64 + vByte);
}

function isHH3MigrationError(
  context: ErrorContext,
): ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR | undefined {
  if (
    context.errorChain.some(
      (candidate) =>
        hasErrorClassName(candidate, UsingHardhat2PluginError) ||
        (context.lowercaseMessageByError.get(candidate) ?? "").includes(
          HH2_PLUGIN_ERROR_MARKER,
        ),
    )
  ) {
    return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
  }

  for (const lowercaseMessage of context.lowercaseMessageByError.values()) {
    if (includesAny(lowercaseMessage, ...HH3_MIGRATION_MARKERS)) {
      return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
    }
  }

  if (
    context.errorChain.some(
      (candidate) => candidate.stack?.includes("@nomiclabs") === true,
    )
  ) {
    return ErrorCategory.HH2_TO_HH3_MIGRATION_ERROR;
  }
}

protected get gatewayUrl(): string {
    const url = this.hre.starknet.networkConfig.url;
    if (this.externalServer.isDockerDesktop) {
        for (const protocol of ["http://", "https://", ""]) {
            for (const host of ["localhost", "127.0.0.1"]) {
                if (url === `${protocol}${host}`) {
                    return `${protocol}${DOCKER_HOST}`;
                }

                const prefix = `${protocol}${host}:`;
                if (url.startsWith(prefix)) {
                    return url.replace(prefix, `${protocol}${DOCKER_HOST}:`);
                }
            }
        }
    }
    return url;
}

function getSerializedTx(_tx: JsonRpcTx, emulateSignatureComponents = false): string {
  let signature;

  const tx = toTransactionSerializable(_tx);
  const type = getTransactionType(tx) as "eip2930" | "eip4844" | "eip7702" | "eip1559" | "legacy" | undefined;

  // For arbitrum - part of their estimation flow at nitro
  // TEMORARILY DISABLED DUE TO CRASH REPORTED IN ISSUE #258
  if (emulateSignatureComponents) {
    signature = {
      v: BigInt(0),
      r: RANDOM_R_COMPONENT as `0x${string}`,
      s: RANDOM_S_COMPONENT as `0x${string}`
    }
  }

  return serializeTransaction ({
    to: tx.to,
    maxFeePerGas: tx.maxFeePerGas,
    maxPriorityFeePerGas: tx.maxPriorityFeePerGas,
    data: tx.data,
    value: tx.value,
    chainId: tx.chainId,
    type,
    nonce: tx.nonce,
  } as TransactionSerializableLegacy, signature)
}

function overwriteBigNumberWithin(
  _super: (...args: any[]) => any,
  chaiUtils: Chai.ChaiUtils,
) {
  return function (this: Chai.AssertionStatic, ...args: any[]) {
    const [startArg, finishArg] = args;
    const expectedFlag = chaiUtils.flag(this, "object");

    if (isBigInt(expectedFlag) || isBigInt(startArg) || isBigInt(finishArg)) {
      const expected = toBigInt(expectedFlag);
      const start = toBigInt(startArg);
      const finish = toBigInt(finishArg);
      this.assert(
        start <= expected && expected <= finish,
        `expected ${expected} to be within ${start}..${finish}`,
        `expected ${expected} to not be within ${start}..${finish}`,
        expected,
        [start, finish],
      );
    } else {
      _super.apply(this, args);
    }
  };
}

function bindCompile(
  solc: Solc,
  isVersion6OrNewer: boolean,
): CompileWrapper | undefined {
  if (isVersion6OrNewer) {
    if (
      solc._solidity_compile !== null &&
      solc._solidity_compile !== undefined
    ) {
      return solc.cwrap("solidity_compile", "string", [
        "string",
        "number",
        "number",
      ]);
    }
  } else {
    if (
      solc._solidity_compile !== null &&
      solc._solidity_compile !== undefined
    ) {
      return solc.cwrap("solidity_compile", "string", ["string", "number"]);
    }
    if (solc._compileStandard !== null && solc._compileStandard !== undefined) {
      return solc.cwrap("compileStandard", "string", ["string", "number"]);
    }
  }

  return undefined;
}

function writeAuthFiles(): void {
  // Pre-seed htpasswd with a known user so verdaccio accepts publishes
  // without any interactive login. Format: username:{SHA}base64(sha1(password))
  const passwordHash =
    "{SHA}" + createHash("sha1").update("test").digest("base64");

  writeFileSync(VERDACCIO_HTPASSWD, `test:${passwordHash}\n`);

  // Write .npmrc with basic auth (base64 of "test:test") scoped to the registry
  const basicAuth = Buffer.from("test:test").toString("base64");

  writeFileSync(
    VERDACCIO_NPMRC,
    `//${VERDACCIO_HOST}:${VERDACCIO_PORT}/:_auth=${basicAuth}\n`,
  );
}

function createMarkerFile(projectRoot: string, reasons: string[]) {
	const markerPath = join(projectRoot, MARKER_FILE);
	const content = `HARDHAT-DEPLOY V2 - V1 PATTERNS DETECTED

This file was created because hardhat-deploy v2 detected v1 patterns in your project.
You can delete this file after reading.

Detected issues:
${reasons.map((r) => `  - ${r}`).join('\n')}

To resolve this, either:

1. Install hardhat-deploy v1 instead:
   npm uninstall hardhat-deploy
   ${V1_INSTALL_CMD}

2. Migrate your project to v2:
   ${MIGRATION_URL}

For more information, see the migration guide.
`;

	try {
		writeFileSync(markerPath, content, 'utf-8');
	} catch (e) {
		// Failed to write marker file - continue anyway
	}
}

function buildContractCompletion(
  _node: ContractDefinition,
  range: {
    start: VSCodePosition;
    end: VSCodePosition;
  },
  style: NatspecStyle
) {
  let text = "";
  if (style === NatspecStyle.MULTI_LINE) {
    text += "\n * @title $1\n";
    text += " * @author $2\n";
    text += " * @notice $3\n";
  } else if (style === NatspecStyle.SINGLE_LINE) {
    text += " @title $1\n";
    text += "/// @author $2\n";
    text += "/// @notice $3";
  }

  return {
    label: "NatSpec contract documentation",
    textEdit: {
      range,
      newText: text,
    },
    insertTextFormat: InsertTextFormat.Snippet,
  };
}

function _sanitizeGasData(data: GasData, options: GasReporterOptions) {
  delete options.proxyResolver;

  delete (data as any).addressCache;
  delete (data as any).codeHashMap;
  delete data.provider;

  if (!options.includeBytecodeInJSON) {
    data.deployments.forEach(deployment => {
      delete (deployment as any).bytecode;
      delete (deployment as any).deployedBytecode;
    })
  }

  if (options.coinmarketcap){
    options.coinmarketcap = "[REDACTED]";
  }

  if (options.etherscan) {
    options.etherscan = "[REDACTED]";
  }

  // Options deprecated in 2.3.0
  if (options.L1Etherscan){
    options.L1Etherscan = "[REDACTED]";
  }

  if (options.L2Etherscan){
    options.L2Etherscan = "[REDACTED]";
  }
}
